// NOTE: Discord claims arrive in `idToken`, not `userInfo` — Discord does not
// issue a real JWT id_token so FusionAuth routes userinfo claims differently.
function reconcile(user, registration, idToken, accessToken, userInfo) {
  if (idToken.avatar && typeof idToken.avatar === 'string') {
    var isAnimated = idToken.avatar.startsWith('a_');
    user.imageUrl = 'https://cdn.discordapp.com/avatars/' + idToken.id + '/' + idToken.avatar + '.' + (isAnimated ? 'gif' : 'png') + '?size=256';
  } else {
    var defaultIndex = 0;
    if (idToken.discriminator === '0') {
      try { defaultIndex = Number(BigInt(idToken.id) >> BigInt(22)) % 6; } catch(e) { defaultIndex = 0; }
    } else {
      defaultIndex = parseInt(idToken.discriminator, 10) % 5;
    }
    user.imageUrl = 'https://cdn.discordapp.com/embed/avatars/' + defaultIndex + '.png';
  }
  if (idToken.global_name) { user.fullName = idToken.global_name; }
  else if (idToken.username) { user.fullName = idToken.discriminator && idToken.discriminator !== '0' ? idToken.username + '#' + idToken.discriminator : idToken.username; }
  if (idToken.username) { user.username = idToken.username; }
  if (typeof idToken.verified !== 'undefined') { user.verified = idToken.verified; }
  if (idToken.locale) { user.preferredLanguages = [idToken.locale]; }
  user.data = user.data || {};
  user.data.discord = {
    id: idToken.id, username: idToken.username, discriminator: idToken.discriminator,
    globalName: idToken.global_name || null, locale: idToken.locale || null,
    mfaEnabled: idToken.mfa_enabled || false, premiumType: idToken.premium_type || 0,
    flags: idToken.public_flags || 0,
    banner: idToken.banner ? 'https://cdn.discordapp.com/banners/' + idToken.id + '/' + idToken.banner + '.png?size=600' : null,
    accentColor: (typeof idToken.accent_color === 'number') ? '#' + idToken.accent_color.toString(16).padStart(6, '0') : null
  };
  registration.data = registration.data || {};
  registration.data.discord = { id: idToken.id, username: idToken.username };
}
